154	/**
155	 * Constructs an InferenceSession using a model file located at the specified path.
156	 * @param {string} pretrained_model_name_or_path The path to the directory containing the model file.
157	 * @param {string} fileName The name of the model file.
158	 * @param {import('./utils/hub.js').PretrainedModelOptions} options Additional options for loading the model.
159	 * @returns {Promise<{buffer_or_path: Uint8Array|string, session_options: Object, session_config: Object}>} A Promise that resolves to the data needed to create an InferenceSession object.
160	 * @private
161	 */
162	async function getSession(pretrained_model_name_or_path, fileName, options) {
163	    let custom_config = options.config?.['transformers.js_config'] ?? {};
164	
165	    let device = options.device ?? custom_config.device;
166	    if (device && typeof device !== 'string') {
167	        if (device.hasOwnProperty(fileName)) {
168	            device = device[fileName];
169	        } else {
170	            console.warn(`device not specified for "${fileName}". Using the default device.`);
171	            device = null;
172	        }
173	    }
174	
175	    // If the device is not specified, we use the default (supported) execution providers.
176	    const selectedDevice = /** @type {import("./utils/devices.js").DeviceType} */(
177	        device ?? (apis.IS_NODE_ENV ? 'cpu' : 'wasm')
178	    );
179	
180	    const executionProviders = deviceToExecutionProviders(selectedDevice);
181	
182	    // Update custom config with the selected device's config, if it exists
183	    const device_config = custom_config.device_config ?? {};
184	    if (device_config.hasOwnProperty(selectedDevice)) {
185	        custom_config = {
186	            ...custom_config,
187	            ...device_config[selectedDevice],
188	        };
189	    }
190	
191	    // If options.dtype is specified, we use it to choose the suffix for the model file.
192	    // Otherwise, we use the default dtype for the device.
193	    let dtype = options.dtype ?? custom_config.dtype;
194	    if (typeof dtype !== 'string') {
195	        if (dtype && dtype.hasOwnProperty(fileName)) {
196	            dtype = dtype[fileName];
197	        } else {
198	            dtype = DEFAULT_DEVICE_DTYPE_MAPPING[selectedDevice] ?? DATA_TYPES.fp32;
199	            console.warn(`dtype not specified for "${fileName}". Using the default dtype (${dtype}) for this device (${selectedDevice}).`);
200	        }
201	    }
202	
203	    if (dtype === DATA_TYPES.auto) {
204	        // Try to choose the auto dtype based on the custom config
205	        let config_dtype = custom_config.dtype;
206	        if (typeof config_dtype !== 'string') {
207	            config_dtype = config_dtype?.[fileName];
208	        }
209	
210	        if (config_dtype && config_dtype !== DATA_TYPES.auto && DATA_TYPES.hasOwnProperty(config_dtype)) {
211	            // Defined by the config, and is not "auto"
212	            dtype = config_dtype;
213	        } else {
214	            // Choose default dtype based on device, falling back to fp32
215	            dtype = DEFAULT_DEVICE_DTYPE_MAPPING[selectedDevice] ?? DATA_TYPES.fp32;
216	        }
217	    }
218	
219	    const selectedDtype = /** @type {import("./utils/dtypes.js").DataType} */(dtype);
220	
221	    if (!DEFAULT_DTYPE_SUFFIX_MAPPING.hasOwnProperty(selectedDtype)) {
222	        throw new Error(`Invalid dtype: ${selectedDtype}. Should be one of: ${Object.keys(DATA_TYPES).join(', ')}`);
223	    } else if (selectedDtype === DATA_TYPES.fp16 && selectedDevice === 'webgpu' && !(await isWebGpuFp16Supported())) {
224	        throw new Error(`The device (${selectedDevice}) does not support fp16.`);
225	    }
226	
227	    // Only valid for models with a decoder
228	    const kv_cache_dtype_config = custom_config.kv_cache_dtype;
229	    const kv_cache_dtype = kv_cache_dtype_config
230	        ? (typeof kv_cache_dtype_config === 'string'
231	            ? kv_cache_dtype_config
232	            : kv_cache_dtype_config[selectedDtype] ?? 'float32')
233	        : undefined;
234	
235	    if (kv_cache_dtype && !['float32', 'float16'].includes(kv_cache_dtype)) {
236	        throw new Error(`Invalid kv_cache_dtype: ${kv_cache_dtype}. Should be one of: float32, float16`);
237	    }
238	
239	    const session_config = {
240	        dtype: selectedDtype,
241	        kv_cache_dtype,
242	        device: selectedDevice,
243	    }
244	
245	    // Construct the model file name
246	    const suffix = DEFAULT_DTYPE_SUFFIX_MAPPING[selectedDtype];
247	    const baseName = `${fileName}${suffix}.onnx`;
248	    const modelFileName = `${options.subfolder ?? ''}/${baseName}`;
249	
250	    const session_options = { ...options.session_options };
251	
252	    // Overwrite `executionProviders` if not specified
253	    session_options.executionProviders ??= executionProviders;
254	
255	    // Overwrite `freeDimensionOverrides` if specified in config and not set in session options
256	    const free_dimension_overrides = custom_config.free_dimension_overrides;
257	    if (free_dimension_overrides) {
258	        session_options.freeDimensionOverrides ??= free_dimension_overrides;
259	    } else if (selectedDevice.startsWith('webnn') && !session_options.freeDimensionOverrides) {
260	        console.warn(
261	            `WebNN does not currently support dynamic shapes and requires 'free_dimension_overrides' to be set in config.json, preferably as a field within config["transformers.js_config"]["device_config"]["${selectedDevice}"]. ` +
262	            `When 'free_dimension_overrides' is not set, you may experience significant performance degradation.`
263	        );
264	    }
265	
266	    const return_path = apis.IS_NODE_ENV && env.useFSCache;
267	    const bufferOrPathPromise = getModelFile(pretrained_model_name_or_path, modelFileName, true, options, return_path);
268	
269	    // Handle onnx external data files
270	    const use_external_data_format = options.use_external_data_format ?? custom_config.use_external_data_format;
271	    /** @type {Promise<string|{path: string, data: Uint8Array}>[]} */
272	    let externalDataPromises = [];
273	    if (use_external_data_format) {
274	        let external_data_format;
275	        if (typeof use_external_data_format === 'object') {
276	            if (use_external_data_format.hasOwnProperty(baseName)) {
277	                external_data_format = use_external_data_format[baseName];
278	            } else if (use_external_data_format.hasOwnProperty(fileName)) {
279	                external_data_format = use_external_data_format[fileName];
280	            } else {
281	                external_data_format = false;
282	            }
283	        } else {
284	            external_data_format = use_external_data_format;
285	        }
286	
287	        const num_chunks = +external_data_format; // (false=0, true=1, number remains the same)
288	        if (num_chunks > MAX_EXTERNAL_DATA_CHUNKS) {
289	            throw new Error(`The number of external data chunks (${num_chunks}) exceeds the maximum allowed value (${MAX_EXTERNAL_DATA_CHUNKS}).`);
290	        }
291	        for (let i = 0; i < num_chunks; ++i) {
292	            const path = `${baseName}_data${i === 0 ? '' : '_' + i}`;
293	            const fullPath = `${options.subfolder ?? ''}/${path}`;
294	            externalDataPromises.push(new Promise(async (resolve, reject) => {
295	                const data = await getModelFile(pretrained_model_name_or_path, fullPath, true, options, return_path);
296	                resolve(data instanceof Uint8Array ? { path, data } : path);
297	            }));
298	        }
299	
300	    } else if (session_options.externalData !== undefined) {
301	        externalDataPromises = session_options.externalData.map(async (ext) => {
302	            // if the external data is a string, fetch the file and replace the string with its content
303	            // @ts-expect-error TS2339
304	            if (typeof ext.data === "string") {
305	                // @ts-expect-error TS2339
306	                const ext_buffer = await getModelFile(pretrained_model_name_or_path, ext.data, true, options);
307	                // @ts-expect-error TS2698
308	                return { ...ext, data: ext_buffer };
309	            }
310	            return ext;
311	        });
312	    }
313	
314	    if (externalDataPromises.length > 0) {
315	        const externalData = await Promise.all(externalDataPromises);
316	        if (!apis.IS_NODE_ENV) {
317	            session_options.externalData = externalData;
318	        }
319	    }
320	
321	    if (selectedDevice === 'webgpu') {
322	        const shapes = getCacheShapes(options.config, {
323	            prefix: 'present',
324	        });
325	        if (Object.keys(shapes).length > 0 && !isONNXProxy()) {
326	            // Only set preferredOutputLocation if shapes are present and we aren't proxying ONNX
327	            /** @type {Record<string, import('onnxruntime-common').Tensor.DataLocation>} */
328	            const preferredOutputLocation = {};
329	            for (const key in shapes) {
330	                preferredOutputLocation[key] = 'gpu-buffer';
331	            }
332	            session_options.preferredOutputLocation = preferredOutputLocation;
333	        }
334	    }
335	
336	    const buffer_or_path = await bufferOrPathPromise;
337	
338	    return { buffer_or_path, session_options, session_config };
339	}
340	
341	/**
342	 * Helper function to create multiple InferenceSession objects.
343	 * 
344	 * @param {string} pretrained_model_name_or_path The path to the directory containing the model file.
345	 * @param {Record<string, string>} names The names of the model files to load.
346	 * @param {import('./utils/hub.js').PretrainedModelOptions} options Additional options for loading the model.
347	 * @returns {Promise<Record<string, any>>} A Promise that resolves to a dictionary of InferenceSession objects.
348	 * @private
349	 */
350	async function constructSessions(pretrained_model_name_or_path, names, options) {
351	    return Object.fromEntries(await Promise.all(
352	        Object.keys(names).map(async (name) => {
353	            const { buffer_or_path, session_options, session_config } = await getSession(pretrained_model_name_or_path, names[name], options);
354	            const session = await createInferenceSession(buffer_or_path, session_options, session_config);
355	            return [name, session];
356	        })
357	    ));
358	}
