377	/**
378	 * Validate model inputs
379	 * @param {Object} session The InferenceSession object that will be run.
380	 * @param {Object} inputs The inputs to check.
381	 * @returns {Record<string, Tensor>} The checked inputs.
382	 * @throws {Error} If any inputs are missing.
383	 * @private
384	 */
385	function validateInputs(session, inputs) {
386	    /**
387	     * NOTE: Create either a shallow or deep copy based on `onnx.wasm.proxy`
388	     * @type {Record<string, Tensor>}
389	     */
390	    const checkedInputs = Object.create(null);
391	    const missingInputs = [];
392	    for (const inputName of session.inputNames) {
393	        const tensor = inputs[inputName];
394	        // Rare case where one of the model's input names corresponds to a built-in
395	        // object name (e.g., toString), which would cause a simple (!tensor) check to fail,
396	        // because it's not undefined but a function.
397	        if (!(tensor instanceof Tensor)) {
398	            missingInputs.push(inputName);
399	            continue;
400	        }
401	        // NOTE: When `env.wasm.proxy is true` the tensor is moved across the Worker
402	        // boundary, transferring ownership to the worker and invalidating the tensor.
403	        // So, in this case, we simply sacrifice a clone for it.
404	        checkedInputs[inputName] = isONNXProxy() ? tensor.clone() : tensor;
405	    }
406	    if (missingInputs.length > 0) {
407	        throw new Error(
408	            `An error occurred during model execution: "Missing the following inputs: ${missingInputs.join(', ')}.`);
409	    }
410	
411	    const numInputsProvided = Object.keys(inputs).length;
412	    const numInputsNeeded = session.inputNames.length;
413	    if (numInputsProvided > numInputsNeeded) {
414	        // No missing inputs, but too many inputs were provided.
415	        // Warn the user and ignore the extra inputs.
416	        let ignored = Object.keys(inputs).filter(inputName => !session.inputNames.includes(inputName));
417	        console.warn(`WARNING: Too many inputs were provided (${numInputsProvided} > ${numInputsNeeded}). The following inputs will be ignored: "${ignored.join(', ')}".`);
418	    }
419	
420	    return checkedInputs;
421	}
422	
423	/**
424	 * Executes an InferenceSession using the specified inputs.
425	 * NOTE: `inputs` must contain at least the input names of the model.
426	 *  - If additional inputs are passed, they will be ignored.
427	 *  - If inputs are missing, an error will be thrown.
428	 * 
429	 * @param {Object} session The InferenceSession object to run.
430	 * @param {Object} inputs An object that maps input names to input tensors.
431	 * @returns {Promise<Object>} A Promise that resolves to an object that maps output names to output tensors.
432	 * @private
433	 */
434	async function sessionRun(session, inputs) {
435	    const checkedInputs = validateInputs(session, inputs);
436	    try {
437	        // pass the original ort tensor
438	        const ortFeed = Object.fromEntries(Object.entries(checkedInputs).map(([k, v]) => [k, v.ort_tensor]));
439	        const output = await runInferenceSession(session, ortFeed);
440	        return replaceTensors(output);
441	    } catch (e) {
442	        // Error messages can be long (nested) and uninformative. For this reason,
443	        // we apply minor formatting to show the most important information
444	        const formatted = Object.fromEntries(Object.entries(checkedInputs)
445	            .map(([k, tensor]) => {
446	                // Extract these properties from the underlying ORT tensor
447	                const unpacked = {
448	                    type: tensor.type,
449	                    dims: tensor.dims,
450	                    location: tensor.location,
451	                }
452	                if (unpacked.location !== "gpu-buffer") {
453	                    // Only return the data if it's not a GPU buffer
454	                    unpacked.data = tensor.data;
455	                }
456	                return [k, unpacked];
457	            }));
458	
459	        // This usually occurs when the inputs are of the wrong type.
460	        console.error(`An error occurred during model execution: "${e}".`);
461	        console.error('Inputs given to model:', formatted);
462	        throw e;
463	    }
464	}
465	
466	/**
467	 * Replaces ONNX Tensor objects with custom Tensor objects to support additional functions.
468	 * @param {Object} obj The object to replace tensor objects in.
469	 * @returns {Object} The object with tensor objects replaced by custom Tensor objects.
470	 * @private
471	 */
472	function replaceTensors(obj) {
473	    for (let prop in obj) {
474	        if (isONNXTensor(obj[prop])) {
475	            obj[prop] = new Tensor(obj[prop]);
476	        } else if (typeof obj[prop] === 'object') {
477	            replaceTensors(obj[prop]);
478	        }
479	    }
480	    return obj;
481	}
