2	/**
3	 * @file Tokenizers are used to prepare textual inputs for a model.
4	 * 
5	 * **Example:** Create an `AutoTokenizer` and use it to tokenize a sentence.
6	 * This will automatically detect the tokenizer type based on the tokenizer class defined in `tokenizer.json`.
7	 * ```javascript
8	 * import { AutoTokenizer } from '@huggingface/transformers';
9	 * 
10	 * const tokenizer = await AutoTokenizer.from_pretrained('Xenova/bert-base-uncased');
11	 * const { input_ids } = await tokenizer('I love transformers!');
12	 * // Tensor {
13	 * //   data: BigInt64Array(6) [101n, 1045n, 2293n, 19081n, 999n, 102n],
14	 * //   dims: [1, 6],
15	 * //   type: 'int64',
16	 * //   size: 6,
17	 * // }
18	 * ```
19	 * 
20	 * @module tokenizers
21	 */
