60	
61	/**
62	 * Loads a tokenizer from the specified path.
63	 * @param {string} pretrained_model_name_or_path The path to the tokenizer directory.
64	 * @param {PretrainedTokenizerOptions} options Additional options for loading the tokenizer.
65	 * @returns {Promise<any[]>} A promise that resolves with information about the loaded tokenizer.
66	 */
67	async function loadTokenizer(pretrained_model_name_or_path, options) {
68	
69	    const info = await Promise.all([
70	        getModelJSON(pretrained_model_name_or_path, 'tokenizer.json', true, options),
71	        getModelJSON(pretrained_model_name_or_path, 'tokenizer_config.json', true, options),
72	    ])
73	
74	    // Override legacy option if `options.legacy` is not null
75	    if (options.legacy !== null) {
76	        info[1].legacy = options.legacy;
77	    }
78	    return info;
79	}
